#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef unsigned long long ull;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10;ull a[N],b[N],c[N];int n,m;
int head[N],des[N],nxt[N],cgt,ou[N],Ans,Cur;bool vis[N];
ull sd=998244353*ull(1e9+7)*time(0);
inline ull Rand()
{
	sd^=sd<<59;sd^=sd>>47;sd^=sd<<41;sd^=sd>>31;sd^=sd<<29;
	sd^=sd<<17;sd^=sd<<11;sd^=sd>>7;sd^=sd<<5;return sd;
}
int main()
{
	n=read();m=read();
	rep(1,n,i)Ans+=a[i]=Rand();
	rep(1,m,i)
	{
		int x=read(),y=read();++ou[x];
		b[y]+=a[x];c[y]+=a[x];
	}
	rep(1,n,i)Cur+=a[i]*ou[i];
	int q=read();while(q--)
	{
		puts("NO");
	}

}
